# Homebrew formula for synckitd. Installs the prebuilt binary for the current
# platform from synckit's GitHub Releases — no Go toolchain needed.
# `brew install --HEAD` builds (pure Go) from source instead.
#
#   brew install yasyf/tap/synckitd
#
# This file is generated by synckit's release.yml from
# .github/formula/synckitd.rb.tmpl on every stable tag — edit the template here,
# not the tap copy. The release job fills 0.30.0 with the v-stripped release
# version and the four __SHA_*__ tokens with the archive checksums from
# dist/checksums.txt.
class Synckitd < Formula
  desc "Generic per-machine sync daemon that drives synckit consumers (cookiesync, reposync)"
  homepage "https://github.com/yasyf/synckit"
  version "0.30.0"

  livecheck do
    url :stable
    strategy :github_latest
  end

  head do
    url "https://github.com/yasyf/synckit.git", branch: "main"
    depends_on "go" => :build
  end

  on_macos do
    on_arm do
      url "https://github.com/yasyf/synckit/releases/download/v#{version}/synckitd_#{version}_darwin_arm64.tar.gz"
      sha256 "4dd14c86643b19d5cdcbd3205a4a2ede6868a058a51a7bfdf106c04d74518bfe"
    end
    on_intel do
      url "https://github.com/yasyf/synckit/releases/download/v#{version}/synckitd_#{version}_darwin_amd64.tar.gz"
      sha256 "d0eb32db8e6f64c415bfa2896a40905f2ad56374f16040b7c9711c544226021b"
    end
  end

  on_linux do
    on_arm do
      url "https://github.com/yasyf/synckit/releases/download/v#{version}/synckitd_#{version}_linux_arm64.tar.gz"
      sha256 "33968f074360e02e5bf9b73168366a2bb9f4164726b6678551801c8c9a2f7cf8"
    end
    on_intel do
      url "https://github.com/yasyf/synckit/releases/download/v#{version}/synckitd_#{version}_linux_amd64.tar.gz"
      sha256 "14baa5e5539a886e85762888064457d440abcabab50a530cf573f1b589969606"
    end
  end

  def install
    if build.head?
      ENV["CGO_ENABLED"] = "0"
      ldflags = "-s -w -X main.version=#{version}"
      system "go", "build", *std_go_args(ldflags: ldflags, output: bin/"synckitd"), "./cmd/synckitd"
    else
      # brew auto-extracts the release tarball; install the bare binary.
      bin.install "synckitd"
    end
  end

  test do
    assert_match version.to_s, shell_output("#{bin}/synckitd --version")
  end
end
